    svg.append("text").attr("transform", "rotate(-90)").attr("x", -(margin.top + iH / 2)).attr("y", 14).attr("text-anchor", "middle").attr("fill", T.fgMuted).style("font-size", FONT_SIZE.axisLabel).text("Influence on pooled estimate");
