    svg.append("text").attr("x", margin.left + iW / 2).attr("y", 18).attr("text-anchor", "middle").attr("fill", T.fg).style("font-size", FONT_SIZE.title).style("font-weight", "600").text(`L'Abb\xE9 plot \u2014 k = ${pts.length}`);
