        const params = [mu, Math.log(tau2), ...new Array(K - 1).fill(0)];
        const negLL_sel = selectionLogLik(params, yi, vi, DEFAULT_CUTS, 1);
        schk(`negLL_sel vs \u2212logLik (mu=${mu}, \u03C4\xB2=${tau2})`, negLL_sel, -ll, 1e-8);
