  function flashBtn(btn, workingLabel, doneLabel, durationMs = 1500) {
    const original = btn.textContent;
    let resolve;
    const promise = new Promise((r) => {
      resolve = r;
    });
    if (workingLabel) {
      btn.disabled = true;
      btn.textContent = workingLabel;
    }
    promise.then(() => {
      btn.disabled = false;
      btn.textContent = doneLabel;
      setTimeout(() => {
        btn.textContent = original;
      }, durationMs);
    });
    return resolve;
  }
